import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import Home from './pages/Home';
import Me from './pages/Me';
import Projects from './pages/Projects';
import Header from './components/Header';
import Background from './components/Background';
import "./styles/styles.css";

export default function App() {
    const [isDarkMode, setIsDarkMode] = useState(false);

    // Fonction pour basculer le thème
    const toggleTheme = () => {
        setIsDarkMode(!isDarkMode);

        if (!isDarkMode) {
            // Applique les variables du thème sombre
            document.documentElement.style.setProperty('--background-color', '#1e1e1e');
            document.documentElement.style.setProperty('--text-color', '#ffffff');
            document.documentElement.style.setProperty('--button-bg', '#333333');
            document.documentElement.style.setProperty('--button-text', '#ffffff');
            document.documentElement.style.setProperty('--primary-color', '#f0f0f0');
            document.documentElement.style.setProperty('--secondary-color', '#2a2a2a');
        } else {
            // Applique les variables du thème clair
            document.documentElement.style.setProperty('--background-color', '#ffffff');
            document.documentElement.style.setProperty('--text-color', '#000000');
            document.documentElement.style.setProperty('--button-bg', '#f0f0f0');
            document.documentElement.style.setProperty('--button-text', '#000000');
            document.documentElement.style.setProperty('--primary-color', '#EC361E');
            document.documentElement.style.setProperty('--secondary-color', '#FCF9CE');
        }
    };

    return (
        <Router>
            <Background>
                <Header />
                <div className="App">
                    {/* Bouton pour changer de thème */}
                    <div style={{ textAlign: 'center', margin: '1rem' }}>
                        <button onClick={toggleTheme} style={{
                            padding: '0.5rem 1rem',
                            borderRadius: 'var(--border-radius)',
                            backgroundColor: 'var(--button-bg)',
                            color: 'var(--button-text)',
                            border: 'none',
                            cursor: 'pointer',
                            transition: 'background-color var(--transition-medium), color var(--transition-medium)'
                        }}>
                            Basculer vers le thème {isDarkMode ? 'Clair' : 'Sombre'}
                        </button>
                    </div>

                    <Routes>
                        <Route path="/" element={<Home />} />
                        <Route path="/me" element={<Me />} />
                        <Route path="/project" element={<Projects />} />
                    </Routes>
                </div>
            </Background>
        </Router>
    );
}
